        />
        {/* Initially hidden, shown on hover */}
        <span className="absolute invisible group-hover:visible text-end" style={{ color: '#f13024', fontWeight: 'bold' }}>DESIGNS</span>
        {/* Initially visible, hidden on hover */}
        <HiArrowRight
          className="text-4xl text-start transition-all duration-300" 
          style={{ color: '#f13024', visibility: 'visible' }}
          aria-hidden
        />
      </Link>
    </div>
  );
};

export default ProjectsBtn;
```

Then, add the necessary CSS to ensure that the `HiArrowRight` is initially visible and the `DESIGNS` span is invisible. On hover of the `.group`, switch these visibilities:

```css
/* Add this to your stylesheet */
.group-hover .text-4xl { /* Selector for the HiArrowRight icon */
  visibility: hidden; /* Hide the icon */
}
.group:hover .text-end { /* Selector for the "DESIGNS" text */
  visibility: visible; /* Show the text */
}
```

In the given snippet, I have used the `visibility` property (which can be `visible` or `hidden`) instead of `display` (which can be `none` or `block`) because it's more appropriate for transitions. If you choose to use `display` you would lose the ability to transition between these states smoothly since the `display` property is not animatable.

